body.script:
//
          // === SETUP ===
          const canvas = document.getElementById('game');
          const ctx = canvas.getContext('2d');
          let W, H;
          function resize() {
            W = canvas.width = window.innerWidth;
            H = canvas.height = window.innerHeight;
          }
          resize();
          window.addEventListener('resize', resize);

          const ARENA = { w: 2400, h: 2000 };
          const PLAYER_R = 8;
          const BULLET_R = 3;
          const BULLET_SPEED = 9.5;
          const PLAYER_SPEED = 2.6;
          const FIRE_COOLDOWN = 200;
          const BOT_SPEED = 1.5;

          // === MAZE & STATE ===
          let walls = [];
          let cellCenters = [];
          let players = [];
          let bullets = [];
          let particles = [];
          let powerups = [];
          let myPlayer = null;
          let keys = {};
          let mouse = { x: 0, y: 0, worldX: 0, worldY: 0 };
          let camera = { x: 0, y: 0 };
          let kills = 0;
          let gameOver = false;
          let running = false;
          let shake = 0;
          let powerStarTimer = 1000;
          let powerAllyTimer = 1000;
          let level = 1;
          let bonusTimer = 30000; // Time until bonus event
          let bonusActiveTimer = 0; // Duration of bonus event

          const rand = (a, b) => Math.random() * (b - a) + a;
          const dist = (a, b) => Math.hypot(a.x - b.x, a.y - b.y);

          // === AUDIO ENGINE (Web Audio API) ===
          let audioCtx = null;
          function initAudio() {
            if (!audioCtx) {
              try { audioCtx = new (window.AudioContext || window.webkitAudioContext)(); } catch(e) {}
            }
          }
          function playTone(freq, duration, type, vol, slideTo) {
            if (!audioCtx) return;
            const osc = audioCtx.createOscillator();
            const gain = audioCtx.createGain();
            osc.type = type || 'sine';
            osc.frequency.setValueAtTime(freq, audioCtx.currentTime);
            if (slideTo) osc.frequency.exponentialRampToValueAtTime(slideTo, audioCtx.currentTime + duration);
            gain.gain.setValueAtTime(vol || 0.1, audioCtx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration);
            osc.connect(gain); gain.connect(audioCtx.destination);
            osc.start(); osc.stop(audioCtx.currentTime + duration);
          }
          function playNoise(duration, vol, filterFreq) {
            if (!audioCtx) return;
            const bufferSize = audioCtx.sampleRate * duration;
            const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
            const data = buffer.getChannelData(0);
            for (let i = 0; i < bufferSize; i++) data[i] = Math.random() * 2 - 1;
            const noise = audioCtx.createBufferSource();
            noise.buffer = buffer;
            const filter = audioCtx.createBiquadFilter();
            filter.type = 'lowpass';
            filter.frequency.setValueAtTime(filterFreq || 1000, audioCtx.currentTime);
            filter.frequency.exponentialRampToValueAtTime(100, audioCtx.currentTime + duration);
            const gain = audioCtx.createGain();
            gain.gain.setValueAtTime(vol || 0.1, audioCtx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration);
            noise.connect(filter); filter.connect(gain); gain.connect(audioCtx.destination);
            noise.start(); noise.stop(audioCtx.currentTime + duration);
          }
          const sfx = {
            shoot: () => playTone(900, 0.08, 'square', 0.04, 400),
            hexShoot: () => { playTone(200, 0.15, 'sawtooth', 0.08, 80); playNoise(0.1, 0.05, 800); },
            empty: () => playTone(150, 0.05, 'sine', 0.03),
            collectStar: () => { playTone(800, 0.08, 'square', 0.08, 1200); setTimeout(() => playTone(1200, 0.06, 'square', 0.06), 60); },
            collectAlly: () => { [400, 600, 800].forEach((f, i) => setTimeout(() => playTone(f, 0.1, 'sine', 0.1), i * 60)); },
            bounce: () => playTone(300, 0.04, 'sine', 0.03),
            wallBreak: () => { playNoise(0.2, 0.15, 1500); playTone(100, 0.1, 'sawtooth', 0.1, 50); },
            hit: () => playTone(120, 0.08, 'square', 0.08, 60),
            explode: () => { playNoise(0.4, 0.2, 800); playTone(80, 0.3, 'sawtooth', 0.1, 30); },
            bonus: () => { playTone(200, 0.5, 'sine', 0.1, 1200); playTone(300, 0.5, 'sawtooth', 0.05, 1500); },
            levelUp: () => { [523, 659, 784, 1046].forEach((f, i) => setTimeout(() => playTone(f, 0.2, 'sine', 0.1), i * 120)); },
            gameOver: () => { [400, 300, 200, 100].forEach((f, i) => setTimeout(() => playTone(f, 0.3, 'sawtooth', 0.1), i * 150)); }
          };

          // === MAZE GENERATION (HEXAGONAL) ===
          const HEX_R = 100;
          const HEX_W = Math.sqrt(3) * HEX_R;
          const HEX_H = 2 * HEX_R;

          function generateMaze() {
            walls = [];
            cellCenters = [];
            const cells = new Map();
            const grid = [];

            for (let q = -10; q <= 10; q++) {
              for (let r = -10; r <= 10; r++) {
                const x = HEX_W * (q + r / 2);
                const y = HEX_H * 3 / 4 * r;
                if (x > -ARENA.w / 2 - HEX_R && x < ARENA.w / 2 + HEX_R &&
                    y > -ARENA.h / 2 - HEX_R && y < ARENA.h / 2 + HEX_R) {
                  const id = q + "," + r;
                  const cell = { id, q, r, x, y, walls: [true, true, true, true, true, true], visited: false };
                  cells.set(id, cell);
                  grid.push(cell);
                }
              }
            }

            const stack = [];
            let current = grid[Math.floor(Math.random() * grid.length)];
            current.visited = true;
            stack.push(current);

            const dirs = [
              { q: 1, r: 0 }, { q: 1, r: -1 }, { q: 0, r: -1 },
              { q: -1, r: 0 }, { q: -1, r: 1 }, { q: 0, r: 1 }
            ];

            while (stack.length > 0) {
              let neighbors = [];
              for (let i = 0; i < 6; i++) {
                const d = dirs[i];
                const nId = (current.q + d.q) + "," + (current.r + d.r);
                const n = cells.get(nId);
                if (n && !n.visited) neighbors.push({ cell: n, dir: i });
              }

              if (neighbors.length > 0) {
                const next = neighbors[Math.floor(Math.random() * neighbors.length)];
                current.walls[next.dir] = false;
                next.cell.walls[(next.dir + 3) % 6] = false;
                next.cell.visited = true;
                stack.push(next.cell);
                current = next.cell;
              } else {
                current = stack.pop();
              }
            }

            for (const c of grid) {
              cellCenters.push({ x: c.x + ARENA.w / 2, y: c.y + ARENA.h / 2 });
              for (let i = 0; i < 6; i++) {
                if (c.walls[i]) {
                  const a1 = (Math.PI / 3) * i - Math.PI / 6;
                  const a2 = (Math.PI / 3) * (i + 1) - Math.PI / 6;
                  const x1 = c.x + Math.cos(a1) * HEX_R;
                  const y1 = c.y + Math.sin(a1) * HEX_R;
                  const x2 = c.x + Math.cos(a2) * HEX_R;
                  const y2 = c.y + Math.sin(a2) * HEX_R;
                  walls.push({ x1, y1, x2, y2 });
                }
              }
            }

            for (const w of walls) {
              w.x1 += ARENA.w / 2; w.y1 += ARENA.h / 2;
              w.x2 += ARENA.w / 2; w.y2 += ARENA.h / 2;
            }
          }

          function createPlayers() {
            players = [];
            const greenSet = new Set();
            while (greenSet.size < 10) greenSet.add(Math.floor(Math.random() * 100));

            for (let i = 0; i < 100; i++) {
              const isGreen = greenSet.has(i);
              let px, py, safe = false, attempts = 0;
              while (!safe && attempts < 50) {
                px = rand(100, ARENA.w - 100);
                py = rand(100, ARENA.h - 100);
                safe = true;
                for (const w of walls) {
                  if (distToSegment({x: px, y: py}, w) < PLAYER_R * 3) {
                    safe = false; break;
                  }
                }
                attempts++;
              }
              players.push({
                id: i,
                x: px, y: py,
                isGreen, alive: true, health: 100, isMe: false,
                angle: rand(0, Math.PI * 2),
                fireTimer: rand(800, 3500),
                moveTimer: rand(600, 2200),
                moveDir: rand(0, Math.PI * 2),
                moving: Math.random() > 0.35,
                hitFlash: 0,
                powerShots: 0
              });
            }
            const greens = players.filter(p => p.isGreen);
            myPlayer = greens[Math.floor(Math.random() * greens.length)];
            myPlayer.isMe = true;
            myPlayer.powerShots = 0;
          }

          function distToSegment(p, w) {
            const l2 = Math.pow(w.x1 - w.x2, 2) + Math.pow(w.y1 - w.y2, 2);
            if (l2 === 0) return dist(p, { x: w.x1, y: w.y1 });
            let t = ((p.x - w.x1) * (w.x2 - w.x1) + (p.y - w.y1) * (w.y2 - w.y1)) / l2;
            t = Math.max(0, Math.min(1, t));
            return dist(p, { x: w.x1 + t * (w.x2 - w.x1), y: w.y1 + t * (w.y2 - w.y1) });
          }

          function resolveCircleSegment(p, w) {
            const l2 = Math.pow(w.x1 - w.x2, 2) + Math.pow(w.y1 - w.y2, 2);
            if (l2 === 0) return;
            let t = ((p.x - w.x1) * (w.x2 - w.x1) + (p.y - w.y1) * (w.y2 - w.y1)) / l2;
            t = Math.max(0, Math.min(1, t));
            const cx = w.x1 + t * (w.x2 - w.x1);
            const cy = w.y1 + t * (w.y2 - w.y1);
            const dx = p.x - cx;
            const dy = p.y - cy;
            const d = Math.hypot(dx, dy);
            if (d < PLAYER_R && d > 0) {
              p.x += (dx / d) * (PLAYER_R - d);
              p.y += (dy / d) * (PLAYER_R - d);
            }
          }

          function spawnBullet(owner, angle, color, fromGreen, type, size) {
            type = type || 'normal';
            size = size || BULLET_R;
            bullets.push({
              x: owner.x + Math.cos(angle) * (PLAYER_R + 3),
              y: owner.y + Math.sin(angle) * (PLAYER_R + 3),
              vx: Math.cos(angle) * BULLET_SPEED,
              vy: Math.sin(angle) * BULLET_SPEED,
              color, life: 110,
              ownerId: owner.id,
              fromGreen,
              type,
              size
            });
          }

          function spawnParticles(x, y, color, count, speed) {
            count = count || 12; speed = speed || 4;
            for (let i = 0; i < count; i++) {
              const a = rand(0, Math.PI * 2);
              const s = rand(0.5, speed);
              particles.push({
                x, y,
                vx: Math.cos(a) * s,
                vy: Math.sin(a) * s,
                life: rand(20, 45),
                maxLife: 45,
                color,
                size: rand(1, 2.6),
              });
            }
          }

          function spawnStarPowerup(x, y, isBonus) {
            if (x === undefined) {
              let px, py, safe = false, attempts = 0;
              while (!safe && attempts < 30) {
                px = rand(100, ARENA.w - 100);
                py = rand(100, ARENA.h - 100);
                safe = true;
                for (const w of walls) {
                  if (distToSegment({x: px, y: py}, w) < 40) {
                    safe = false; break;
                  }
                }
                attempts++;
              }
              x = px; y = py;
            }
            powerups.push({
              x: x, y: y,
              vx: rand(-0.8, 0.8),
              vy: rand(-0.8, 0.8),
              timer: isBonus ? 7000 : 40000,
              rot: 0,
              type: 'star',
              isBonus: isBonus || false
            });
          }

          function spawnAllyPowerup() {
            if (cellCenters.length === 0) return;
            const c = cellCenters[Math.floor(Math.random() * cellCenters.length)];
            powerups.push({
              x: c.x, y: c.y,
              vx: 0, vy: 0,
              timer: 50000,
              rot: 0,
              type: 'ally'
            });
          }

          function update(dt) {
            if (!running) return;

            // Bonus Event Manager (50 Stars for 7 seconds)
            if (bonusActiveTimer > 0) {
              bonusActiveTimer -= dt;
            } else {
              bonusTimer -= dt;
              if (bonusTimer <= 0) {
                bonusActiveTimer = 7000;
                bonusTimer = rand(40000, 70000); // Set next bonus interval
                for(let i=0; i<50; i++) {
                  spawnStarPowerup(undefined, undefined, true);
                }
                sfx.bonus();
              }
            }

            // Powerup Spawning (Stars: 3 to 10)
            let starCount = powerups.filter(p => p.type === 'star' && !p.isBonus).length;
            if (starCount < 3) {
              if (powerStarTimer <= 0) { spawnStarPowerup(); powerStarTimer = 500; }
              else powerStarTimer -= dt;
            } else if (starCount < 10) {
              if (powerStarTimer <= 0) { spawnStarPowerup(); powerStarTimer = rand(2000, 4000); }
              else powerStarTimer -= dt;
            }

            // Powerup Spawning (Ally Hex: 4 to 12)
            let allyCount = powerups.filter(p => p.type === 'ally').length;
            if (allyCount < 4) {
              if (powerAllyTimer <= 0) { spawnAllyPowerup(); powerAllyTimer = 500; }
              else powerAllyTimer -= dt;
            } else if (allyCount < 12) {
              if (powerAllyTimer <= 0) { spawnAllyPowerup(); powerAllyTimer = rand(2000, 4000); }
              else powerAllyTimer -= dt;
            }

            // Powerups Update
            for (let i = powerups.length - 1; i >= 0; i--) {
              const pu = powerups[i];
              pu.timer -= dt;
              pu.rot += 0.03;
              
              if (pu.type === 'star') {
                pu.x += pu.vx; pu.y += pu.vy;
                if (pu.x < 30) { pu.x = 30; pu.vx *= -1; }
                if (pu.x > ARENA.w - 30) { pu.x = ARENA.w - 30; pu.vx *= -1; }
                if (pu.y < 30) { pu.y = 30; pu.vy *= -1; }
                if (pu.y > ARENA.h - 30) { pu.y = ARENA.h - 30; pu.vy *= -1; }
              }

              if (pu.timer <= 0) {
                powerups.splice(i, 1);
                continue;
              }

              // Player Collision
              if (myPlayer && myPlayer.alive && dist(myPlayer, pu) < PLAYER_R + 14) {
                if (pu.type === 'star') {
                  myPlayer.powerShots += 10;
                  spawnParticles(pu.x, pu.y, pu.isBonus ? '#ff3a3a' : (pu.timer <= 10000 ? '#3aafff' : '#ff3a3a'), 20, 5);
                  powerups.splice(i, 1);
                  sfx.collectStar();
                } else if (pu.type === 'ally') {
                  myPlayer.powerShots += 5;
                  // Also grant all green allies 5 shots!
                  players.forEach(pl => {
                    if (pl.isGreen && pl.alive && !pl.isMe) pl.powerShots = 5;
                  });
                  spawnParticles(pu.x, pu.y, '#a020f0', 30, 6);
                  powerups.splice(i, 1);
                  sfx.collectAlly();
                }
              }
            }

            // Ally Bots Collecting Ally Powerups
            for (const p of players) {
              if (!p.alive || !p.isGreen || p.isMe) continue;
              for (let i = powerups.length - 1; i >= 0; i--) {
                const pu = powerups[i];
                if (pu.type === 'ally' && dist(p, pu) < PLAYER_R + 14) {
                  p.powerShots = 5; // 5 shots only
                  spawnParticles(pu.x, pu.y, '#a020f0', 20, 5);
                  powerups.splice(i, 1);
                }
              }
            }

            if (myPlayer && myPlayer.alive) {
              let mx = 0, my = 0;
              if (keys['w']) my -= 1;
              if (keys['s']) my += 1;
              if (keys['a']) mx -= 1;
              if (keys['d']) mx += 1;
              if (mx || my) {
                const len = Math.hypot(mx, my);
                mx /= len; my /= len;
                myPlayer.x += mx * PLAYER_SPEED;
                myPlayer.y += my * PLAYER_SPEED;
              }
              for (const w of walls) resolveCircleSegment(myPlayer, w);
              myPlayer.x = Math.max(PLAYER_R, Math.min(ARENA.w - PLAYER_R, myPlayer.x));
              myPlayer.y = Math.max(PLAYER_R, Math.min(ARENA.h - PLAYER_R, myPlayer.y));

              const dx = mouse.worldX - myPlayer.x;
              const dy = mouse.worldY - myPlayer.y;
              myPlayer.angle = Math.atan2(dy, dx);

              myPlayer.fireTimer -= dt;
              if (keys['q'] && myPlayer.fireTimer <= 0) {
                let bColor = '#39ff14';
                let bType = 'normal';
                let bSize = BULLET_R;
                if (myPlayer.powerShots > 0) {
                  bColor = '#ffdd00';
                  bType = 'hex';
                  bSize = BULLET_R * 1.8;
                  myPlayer.powerShots--;
                  sfx.hexShoot();
                  if (myPlayer.powerShots === 0) sfx.empty();
                } else {
                  sfx.shoot();
                }
                spawnBullet(myPlayer, myPlayer.angle, bColor, true, bType, bSize);
                myPlayer.fireTimer = FIRE_COOLDOWN;
                spawnParticles(
                  myPlayer.x + Math.cos(myPlayer.angle) * (PLAYER_R + 3),
                  myPlayer.y + Math.sin(myPlayer.angle) * (PLAYER_R + 3),
                  bColor, 5, 2
                );
                shake = 3;
              }
            }

            for (const p of players) {
              if (!p.alive || p.isMe) continue;
              p.hitFlash = Math.max(0, p.hitFlash - dt);

              p.moveTimer -= dt;
              if (p.moveTimer <= 0) {
                p.moving = Math.random() > 0.25;
                p.moveDir = rand(0, Math.PI * 2);
                p.moveTimer = rand(700, 2400);
              }
              if (p.moving) {
                p.x += Math.cos(p.moveDir) * BOT_SPEED;
                p.y += Math.sin(p.moveDir) * BOT_SPEED;
                p.angle = p.moveDir;
              }
              for (const w of walls) resolveCircleSegment(p, w);
              if (p.x < PLAYER_R) { p.x = PLAYER_R; p.moveDir = Math.PI - p.moveDir; }
              if (p.x > ARENA.w - PLAYER_R) { p.x = ARENA.w - PLAYER_R; p.moveDir = Math.PI - p.moveDir; }
              if (p.y < PLAYER_R) { p.y = PLAYER_R; p.moveDir = -p.moveDir; }
              if (p.y > ARENA.h - PLAYER_R) { p.y = ARENA.h - PLAYER_R; p.moveDir = -p.moveDir; }

              p.fireTimer -= dt;
              if (p.fireTimer <= 0) {
                let fa = p.moving ? p.moveDir + rand(-0.4, 0.4) : rand(0, Math.PI * 2);
                let bColor = p.isGreen ? '#7fff5a' : '#ff5530';
                let bType = 'normal';
                let bSize = BULLET_R;
                let fireDelay = rand(1400, 4500);

                // Green Allies actively break walls if they have power shots
                if (p.isGreen && p.powerShots > 0 && walls.length > 0) {
                  let nearestWall = null;
                  let minDist = Infinity;
                  for (const w of walls) {
                    const d = distToSegment(p, w);
                    if (d < minDist) {
                      minDist = d;
                      nearestWall = w;
                    }
                  }
                  if (nearestWall && minDist < 800) { // Allies shoot walls from further away
                    const mx = (nearestWall.x1 + nearestWall.x2) / 2;
                    const my = (nearestWall.y1 + nearestWall.y2) / 2;
                    fa = Math.atan2(my - p.y, mx - p.x);
                    bColor = '#ffdd00';
                    bType = 'hex';
                    bSize = BULLET_R * 1.8;
                    p.powerShots--;
                    fireDelay = rand(300, 600);
                  }
                }

                spawnBullet(p, fa, bColor, p.isGreen, bType, bSize);
                p.fireTimer = fireDelay;
              }
            }

            for (let i = bullets.length - 1; i >= 0; i--) {
              const b = bullets[i];
              b.x += b.vx; b.y += b.vy; b.life--;
              let hitWall = false;

              for (let j = walls.length - 1; j >= 0; j--) {
                const w = walls[j];
                if (distToSegment(b, w) < b.size) {
                  if (b.type === 'hex') {
                    walls.splice(j, 1);
                    spawnParticles(b.x, b.y, '#ffdd00', 8, 3);
                    bullets.splice(i, 1); hitWall = true;
                    if (b.ownerId === myPlayer.id || (players.find(pl => pl.id === b.ownerId) || {}).isGreen) sfx.wallBreak();
                  } else {
                    spawnParticles(b.x, b.y, b.color, 4, 2);
                    bullets.splice(i, 1); hitWall = true;
                    if (b.ownerId === myPlayer.id) sfx.bounce();
                  }
                  break;
                }
              }
              if (hitWall) continue;

              if (b.life <= 0 || b.x < 0 || b.x > ARENA.w || b.y < 0 || b.y > ARENA.h) {
                bullets.splice(i, 1); continue;
              }

              for (const p of players) {
                if (!p.alive || p.id === b.ownerId) continue;
                if (p.isGreen && b.fromGreen) continue;
                if (dist(b, p) < PLAYER_R + b.size) {
                  p.health -= 25;
                  p.hitFlash = 120;
                  spawnParticles(p.x, p.y, b.color, 6, 3);
                  bullets.splice(i, 1);
                  if (p.health <= 0) {
                    p.alive = false;
                    spawnParticles(p.x, p.y, p.isGreen ? '#39ff14' : '#ff5530', 22, 5);
                    if (b.ownerId === myPlayer.id && !p.isMe) {
                      kills++;
                      document.getElementById('kills').textContent = kills;
                      shake = 6;
                    }
                    if (p.isMe) {
                      shake = 18;
                      setTimeout(endGame, 600);
                    }
                    if (b.ownerId === myPlayer.id) sfx.explode();
                    else if (p.isMe) sfx.explode();
                    else if (Math.random() > 0.7) sfx.explode(); // Cacophony of distant explosions
                  } else {
                    if (p.isMe || b.ownerId === myPlayer.id) sfx.hit();
                  }
                  break;
                }
              }
            }

            for (let i = particles.length - 1; i >= 0; i--) {
              const p = particles[i];
              p.x += p.vx; p.y += p.vy;
              p.vx *= 0.92; p.vy *= 0.92;
              p.life--;
              if (p.life <= 0) particles.splice(i, 1);
            }

            const alive = players.filter(p => p.alive).length;
            document.getElementById('survivors').textContent = alive;
            if (myPlayer) {
              const hp = Math.max(0, myPlayer.health);
              const fill = document.getElementById('health');
              fill.style.width = hp + '%';
              fill.classList.toggle('low', hp <= 35);
              document.getElementById('power').textContent = myPlayer.powerShots || 0;
            }

            if (myPlayer && myPlayer.alive) {
              camera.x += ((myPlayer.x - W/2) - camera.x) * 0.12;
              camera.y += ((myPlayer.y - H/2) - camera.y) * 0.12;
            }
            camera.x = Math.max(0, Math.min(Math.max(0, ARENA.w - W), camera.x));
            camera.y = Math.max(0, Math.min(Math.max(0, ARENA.h - H), camera.y));

            mouse.worldX = mouse.x + camera.x;
            mouse.worldY = mouse.y + camera.y;

            shake *= 0.85;

            // Check Level Complete
            if (walls.length === 0) {
              levelComplete();
            }
          }

          function draw() {
            ctx.fillStyle = '#070a07';
            ctx.fillRect(0, 0, W, H);

            const sx = (Math.random() - 0.5) * shake;
            const sy = (Math.random() - 0.5) * shake;

            ctx.save();
            ctx.translate(-camera.x + sx, -camera.y + sy);

            ctx.strokeStyle = 'rgba(57,255,20,0.045)';
            ctx.lineWidth = 1;
            const gs = 64;
            const sxg = Math.floor(camera.x / gs) * gs;
            const syg = Math.floor(camera.y / gs) * gs;
            ctx.beginPath();
            for (let x = sxg; x < camera.x + W + gs; x += gs) {
              ctx.moveTo(x, camera.y - gs); ctx.lineTo(x, camera.y + H + gs);
            }
            for (let y = syg; y < camera.y + H + gs; y += gs) {
              ctx.moveTo(camera.x - gs, y); ctx.lineTo(camera.x + W + gs, y);
            }
            ctx.stroke();

            ctx.strokeStyle = '#ffdd00';
            ctx.lineWidth = 4;
            ctx.shadowColor = '#ffdd00';
            ctx.shadowBlur = 8;
            ctx.beginPath();
            for (const w of walls) {
              ctx.moveTo(w.x1, w.y1);
              ctx.lineTo(w.x2, w.y2);
            }
            ctx.stroke();
            ctx.shadowBlur = 0;

            ctx.strokeStyle = 'rgba(57,255,20,0.35)';
            ctx.lineWidth = 2;
            ctx.strokeRect(0, 0, ARENA.w, ARENA.h);

            for (const p of particles) {
              ctx.globalAlpha = p.life / p.maxLife;
              ctx.fillStyle = p.color;
              ctx.beginPath();
              ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
              ctx.fill();
            }
            ctx.globalAlpha = 1;

            // Draw Powerups
            for (const pu of powerups) {
              if (pu.type === 'star') {
                const isBlue = !pu.isBonus && pu.timer <= 10000;
                const col = isBlue ? '#3aafff' : '#ff3a3a';
                ctx.save();
                ctx.translate(pu.x, pu.y);
                ctx.rotate(pu.rot);
                ctx.shadowColor = col;
                ctx.shadowBlur = 15;
                ctx.fillStyle = col;
                ctx.beginPath();
                const spikes = 5;
                const outerRadius = 14;
                const innerRadius = 5;
                for (let i = 0; i < spikes * 2; i++) {
                  const r = (i % 2 === 0) ? outerRadius : innerRadius;
                  const a = (Math.PI / spikes) * i - Math.PI / 2;
                  if (i === 0) ctx.moveTo(Math.cos(a) * r, Math.sin(a) * r);
                  else ctx.lineTo(Math.cos(a) * r, Math.sin(a) * r);
                }
                ctx.closePath();
                ctx.fill();
                ctx.restore();
              } else if (pu.type === 'ally') {
                ctx.save();
                ctx.translate(pu.x, pu.y);
                ctx.rotate(pu.rot);
                ctx.shadowColor = '#a020f0';
                ctx.shadowBlur = 18;
                ctx.fillStyle = '#a020f0';
                ctx.strokeStyle = '#e0a0ff';
                ctx.lineWidth = 2;
                ctx.beginPath();
                for (let i = 0; i < 6; i++) {
                  const a = (Math.PI / 3) * i;
                  const x = Math.cos(a) * 12;
                  const y = Math.sin(a) * 12;
                  if (i === 0) ctx.moveTo(x, y);
                  else ctx.lineTo(x, y);
                }
                ctx.closePath();
                ctx.fill();
                ctx.stroke();
                ctx.restore();
              }
            }
            ctx.shadowBlur = 0;

            // Draw Bullets
            for (const b of bullets) {
              ctx.shadowColor = b.color;
              ctx.shadowBlur = 10;
              ctx.fillStyle = b.color;
              if (b.type === 'hex') {
                ctx.save();
                ctx.translate(b.x, b.y);
                ctx.rotate(Math.atan2(b.vy, b.vx));
                ctx.beginPath();
                for (let i = 0; i < 6; i++) {
                  const a = (Math.PI / 3) * i;
                  const x = Math.cos(a) * b.size;
                  const y = Math.sin(a) * b.size;
                  if (i === 0) ctx.moveTo(x, y);
                  else ctx.lineTo(x, y);
                }
                ctx.closePath();
                ctx.fill();
                ctx.restore();
              } else {
                ctx.beginPath();
                ctx.arc(b.x, b.y, b.size, 0, Math.PI * 2);
                ctx.fill();
                ctx.globalAlpha = 0.35;
                ctx.beginPath();
                ctx.arc(b.x - b.vx * 1.5, b.y - b.vy * 1.5, b.size * 0.7, 0, Math.PI * 2);
                ctx.fill();
                ctx.globalAlpha = 1;
              }
            }
            ctx.shadowBlur = 0;

            for (const p of players) {
              if (!p.alive) continue;
              ctx.save();
              ctx.translate(p.x, p.y);
              ctx.rotate(p.angle);

              if (p.isMe) {
                ctx.shadowColor = '#39ff14';
                ctx.shadowBlur = 22;
                ctx.strokeStyle = '#39ff14';
                ctx.lineWidth = 1.5;
                ctx.beginPath();
                ctx.arc(0, 0, PLAYER_R + 5, 0, Math.PI * 2);
                ctx.stroke();
              }

              const body = p.isMe ? '#39ff14'
                        : p.isGreen ? '#4fcc2c'
                        : '#1a1a1a';
              const stroke = p.isMe ? '#e8ffe0'
                          : p.isGreen ? '#39ff14'
                          : '#444';
              const flash = p.hitFlash > 0 ? '#ffffff' : body;

              ctx.fillStyle = flash;
              ctx.strokeStyle = p.hitFlash > 0 ? '#ff3a3a' : stroke;
              ctx.lineWidth = p.isMe ? 2 : 1;
              ctx.beginPath();
              ctx.moveTo(PLAYER_R + 3, 0);
              ctx.lineTo(-PLAYER_R, -PLAYER_R * 0.75);
              ctx.lineTo(-PLAYER_R * 0.4, 0);
              ctx.lineTo(-PLAYER_R, PLAYER_R * 0.75);
              ctx.closePath();
              ctx.fill();
              ctx.stroke();

              ctx.shadowBlur = 0;
              ctx.restore();

              if (!p.isMe && p.health < 100 && p.health > 0) {
                ctx.fillStyle = 'rgba(0,0,0,0.5)';
                ctx.fillRect(p.x - 12, p.y - 18, 24, 2.5);
                ctx.fillStyle = p.isGreen ? '#39ff14' : '#ff5530';
                ctx.fillRect(p.x - 12, p.y - 18, 24 * (p.health / 100), 2.5);
              }
            }

            ctx.restore();

            if (myPlayer && myPlayer.alive && running) {
              const px = myPlayer.x - camera.x + sx;
              const py = myPlayer.y - camera.y + sy;
              ctx.strokeStyle = 'rgba(57,255,20,0.18)';
              ctx.setLineDash([3, 7]);
              ctx.lineWidth = 1;
              ctx.beginPath();
              ctx.moveTo(px, py);
              ctx.lineTo(mouse.x, mouse.y);
              ctx.stroke();
              ctx.setLineDash([]);

              ctx.strokeStyle = '#39ff14';
              ctx.lineWidth = 1.2;
              ctx.beginPath();
              ctx.arc(mouse.x, mouse.y, 11, 0, Math.PI * 2);
              ctx.moveTo(mouse.x - 18, mouse.y); ctx.lineTo(mouse.x - 6, mouse.y);
              ctx.moveTo(mouse.x + 6, mouse.y);  ctx.lineTo(mouse.x + 18, mouse.y);
              ctx.moveTo(mouse.x, mouse.y - 18); ctx.lineTo(mouse.x, mouse.y - 6);
              ctx.moveTo(mouse.x, mouse.y + 6);  ctx.lineTo(mouse.x, mouse.y + 18);
              ctx.stroke();
              ctx.fillStyle = '#39ff14';
              ctx.beginPath();
              ctx.arc(mouse.x, mouse.y, 1.5, 0, Math.PI * 2);
              ctx.fill();
            }

            drawMinimap();
          }

          function drawMinimap() {
            const mw = 190, mh = 190 * (ARENA.h / ARENA.w);
            const mx = W - mw - 28, my = H - mh - 64;

            ctx.fillStyle = 'rgba(8,14,8,0.78)';
            ctx.fillRect(mx, my, mw, mh);
            ctx.strokeStyle = 'rgba(57,255,20,0.35)';
            ctx.lineWidth = 1;
            ctx.strokeRect(mx, my, mw, mh);

            for (const p of players) {
              if (!p.alive) continue;
              const px = mx + (p.x / ARENA.w) * mw;
              const py = my + (p.y / ARENA.h) * mh;
              if (p.isMe) {
                ctx.fillStyle = '#39ff14';
                ctx.shadowColor = '#39ff14';
                ctx.shadowBlur = 6;
                ctx.fillRect(px - 2, py - 2, 4, 4);
                ctx.shadowBlur = 0;
              } else {
                ctx.fillStyle = p.isGreen ? '#7fff5a' : '#3a3a3a';
                ctx.fillRect(px - 1, py - 1, 2, 2);
              }
            }

            const cx = mx + (camera.x / ARENA.w) * mw;
            const cy = my + (camera.y / ARENA.h) * mh;
            const cw = (W / ARENA.w) * mw;
            const ch = (H / ARENA.h) * mh;
            ctx.strokeStyle = 'rgba(57,255,20,0.55)';
            ctx.lineWidth = 1;
            ctx.strokeRect(cx, cy, cw, ch);

            ctx.fillStyle = 'rgba(106,122,96,1)';
            ctx.font = '9px JetBrains Mono';
            ctx.fillText('TACTICAL · MAP', mx, my - 8);
          }

          function endGame() {
            gameOver = true;
            running = false;
            level = 1;
            sfx.gameOver();
            const overlay = document.getElementById('overlay');
            const aliveCount = players.filter(p => p.alive).length;
            overlay.innerHTML =
              '<h1><span class="red">TERMINATED</span></h1>' +
              '<p>GREEN PROTOCOL FAILED · YOUR SIGNAL IS LOST</p>' +
              '<div class="stats">' +
                '<div class="stat"><div class="num">' + kills + '</div><div class="lbl">KILLS</div></div>' +
                '<div class="stat"><div class="num">' + aliveCount + '</div><div class="lbl">SURVIVORS</div></div>' +
              '</div>' +
              '<button id="restart">RETRY PROTOCOL</button>';
            overlay.classList.add('active');
            document.getElementById('restart').onclick = startGame;
          }

          function levelComplete() {
            running = false;
            level++;
            sfx.levelUp();
            const overlay = document.getElementById('overlay');
            const aliveCount = players.filter(p => p.alive).length;
            overlay.innerHTML =
              '<h1><span class="green">MAZE</span><br/>CLEARED</h1>' +
              '<p>ALL YELLOW WALLS DESTROYED · PROTOCOL ADVANCING</p>' +
              '<div class="stats">' +
                '<div class="stat"><div class="num">' + kills + '</div><div class="lbl">KILLS</div></div>' +
                '<div class="stat"><div class="num">' + aliveCount + '</div><div class="lbl">SURVIVORS</div></div>' +
              '</div>' +
              '<button id="next">NEXT LEVEL</button>';
            overlay.classList.add('active');
            document.getElementById('next').onclick = startGame;
          }

          function startGame() {
            initAudio(); // Initialize audio on first user interaction
            generateMaze();
            createPlayers();
            bullets = [];
            particles = [];
            powerups = [];
            powerStarTimer = 1000;
            powerAllyTimer = 1000;
            bonusTimer = 30000; // 30s until first bonus
            bonusActiveTimer = 0;
            kills = 0;
            gameOver = false;
            running = true;
            camera.x = myPlayer.x - W/2;
            camera.y = myPlayer.y - H/2;
            mouse.x = W/2;
            mouse.y = H/2;
            document.getElementById('overlay').classList.remove('active');
            document.getElementById('kills').textContent = 0;
            document.getElementById('power').textContent = 0;
            document.getElementById('health').classList.remove('low');
            
            // Start 2 stars drifting 10 pixels close to the player
            for(let i=0; i<2; i++) {
              const ang = rand(0, Math.PI * 2);
              spawnStarPowerup(myPlayer.x + Math.cos(ang) * 10, myPlayer.y + Math.sin(ang) * 10, false);
            }
          }

          window.addEventListener('keydown', function(e) {
            keys[e.key.toLowerCase()] = true;
            if (['w','a','s','d','q',' '].indexOf(e.key.toLowerCase()) !== -1) e.preventDefault();
          });
          window.addEventListener('keyup', function(e) {
            keys[e.key.toLowerCase()] = false;
          });
          window.addEventListener('mousemove', function(e) {
            mouse.x = e.clientX;
            mouse.y = e.clientY;
          });
          window.addEventListener('mousedown', function(e) {
            if (e.button === 0) keys['q'] = true;
          });
          window.addEventListener('mouseup', function(e) {
            if (e.button === 0) keys['q'] = false;
          });

          document.getElementById('start').onclick = startGame;

          let last = performance.now();
          function loop(now) {
            const dt = Math.min(now - last, 50);
            last = now;
            update(dt);
            draw();
            requestAnimationFrame(loop);
          }
          requestAnimationFrame(loop);
        //
